import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e as i}from"./app-0eb85eb7.js";const r={},d=i('<h1 id="面试-redis" tabindex="-1"><a class="header-anchor" href="#面试-redis" aria-hidden="true">#</a> 面试-Redis</h1><h3 id="介绍一下redis" tabindex="-1"><a class="header-anchor" href="#介绍一下redis" aria-hidden="true">#</a> 介绍一下Redis</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：介绍一下Redis</b></summary><p><b style="color:#f19977;">答：Redis是一个基于Key-Value结构存储的非关系型数据库。数据类型有String、List、Set、Hash、SortedSte有序集合。其基于内存存储速度很快。项目中主要用它来存储热点数据，减轻数据库的压力。有很多地方都用到了Redis，比如商品的秒杀，首页热点数据的显示等等。</b></p></details><h3 id="redis和mysql如何保证一致性" tabindex="-1"><a class="header-anchor" href="#redis和mysql如何保证一致性" aria-hidden="true">#</a> Redis和MySQL如何保证一致性</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Redis和MySQL如何保证一致性</b></summary><p><b style="color:#f19977;">答：当程序需要读取某一个数据时，首先会先尝试去Redis里面加载，如果命中则直接返回，否则则去MySQL查询，查询到之后再把数据缓存到Redis里面。一份数据，同时保存在数据库和Redis里面，当数据发生变化的时候，需要同时更新Redis和MySQL，由于更新是有先后顺序的，并且它不像MySQL中的多表事务操作，可以满足ACID特性。所以就会出现数据一致性问题。解决方式有先更新数据库再更新缓存或者先删除缓存再更新数据库。其都不能完全解决这个问题，可以基于RabbitMQ的可靠性消息通信来实现最终一致性。</b></p></details><h3 id="谈谈缓存雪崩和缓存穿透" tabindex="-1"><a class="header-anchor" href="#谈谈缓存雪崩和缓存穿透" aria-hidden="true">#</a> 谈谈缓存雪崩和缓存穿透</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：谈谈缓存雪崩和缓存穿透</b></summary><p><b style="color:#f19977;">答：缓存雪崩：就是存储在缓存里面的大量数据，在同一个时刻全部过期，原本应该走缓存的大量流量全部请求到了数据库导致服务器崩溃。可以通过给过期时间加随机化偏移或者做集群来解决。<br>缓存穿透：表示是短时间内有大量的不存在的key请求到应用里面，而这些不存在的key在缓存里面又找不到，从而全部穿透到了数据库，造成数据库压力。可以把存在的key放到过滤器中，请求来时如果在过滤器中查不到直接返回不走缓存也不走数据库。另外也可做接口限流、设置黑名单的方式。</b></p></details>',7),t=[d];function l(o,c){return s(),a("div",null,t)}const y=e(r,[["render",l],["__file","面试-Redis.html.vue"]]);export{y as default};
